// Browser-compatible Vapi wrapper for Chrome Extension
// This creates window.Vapi constructor that works without bundlers
// Requires daily-iframe.js to be loaded first

(function() {
  'use strict';

  // Wait for Daily.co to be loaded
  function initVapi() {
    if (typeof window.DailyIframe === 'undefined') {
      console.error('Daily.co library not loaded. Make sure daily-iframe.js is loaded before vapi.min.js');
      return;
    }

    // Simple EventEmitter base class
    class EventEmitter {
      constructor() {
        this.events = {};
      }
      on(event, listener) {
        if (!this.events[event]) this.events[event] = [];
        this.events[event].push(listener);
        return this;
      }
      once(event, listener) {
        const onceWrapper = (...args) => {
          listener(...args);
          this.removeListener(event, onceWrapper);
        };
        return this.on(event, onceWrapper);
      }
      emit(event, ...args) {
        if (this.events[event]) {
          this.events[event].forEach(listener => listener(...args));
          return true;
        }
        return false;
      }
      removeListener(event, listener) {
        if (this.events[event]) {
          this.events[event] = this.events[event].filter(l => l !== listener);
        }
        return this;
      }
      removeAllListeners(event) {
        if (event) {
          delete this.events[event];
        } else {
          this.events = {};
        }
        return this;
      }
    }

    // Vapi class implementation
    class Vapi extends EventEmitter {
      constructor(apiToken, apiBaseUrl) {
        super();
        this.apiToken = apiToken;
        this.apiBaseUrl = apiBaseUrl || 'https://api.vapi.ai';
        this.call = null;
        this.started = false;
        this.speakingTimeout = null;
        this.hasEmittedCallEndedStatus = false;
      }

      async start(assistant, assistantOverrides, squad, workflow) {
        if (this.started) return null;
        this.started = true;

        try {
          // Create web call via Vapi API
          const response = await fetch(`${this.apiBaseUrl}/call/web`, {
            method: 'POST',
            headers: {
              'Authorization': `Bearer ${this.apiToken}`,
              'Content-Type': 'application/json'
            },
            body: JSON.stringify({
              assistant: typeof assistant === 'string' ? undefined : assistant,
              assistantId: typeof assistant === 'string' ? assistant : undefined,
              assistantOverrides,
              squad: typeof squad === 'string' ? undefined : squad,
              squadId: typeof squad === 'string' ? squad : undefined,
              workflow: typeof workflow === 'string' ? undefined : workflow,
              workflowId: typeof workflow === 'string' ? workflow : undefined
            })
          });

          if (!response.ok) {
            const errorData = await response.json().catch(() => ({}));
            throw new Error(errorData.error?.message || `API error: ${response.status}`);
          }

          const webCall = await response.json();
          const isVideoRecordingEnabled = webCall?.artifactPlan?.videoRecordingEnabled ?? false;

          // Create Daily call
          this.call = window.DailyIframe.createCallObject({
            audioSource: true,
            videoSource: isVideoRecordingEnabled
          });

          // Hide Daily iframe
          const iframe = this.call.iframe();
          if (iframe) iframe.style.display = 'none';

          // Set up event listeners
          this.call.on('left-meeting', () => {
            this.emit('call-end');
            if (!this.hasEmittedCallEndedStatus) {
              this.emit('message', {
                type: 'status-update',
                status: 'ended',
                endedReason: 'customer-ended-call'
              });
              this.hasEmittedCallEndedStatus = true;
            }
            this.cleanup();
          });

          this.call.on('error', (error) => {
            this.emit('error', error);
          });

          this.call.on('track-started', async (e) => {
            if (!e || !e.participant) return;
            if (e.participant.local) return;
            if (e.participant.user_name !== 'Vapi Speaker') return;

            if (e.track.kind === 'audio') {
              // Create audio element for assistant voice
              const audio = document.createElement('audio');
              audio.dataset.participantId = e.participant.session_id;
              audio.srcObject = new MediaStream([e.track]);
              audio.autoplay = true;
              audio.muted = false;
              document.body.appendChild(audio);
              await audio.play().catch(err => console.warn('Audio play failed:', err));
            }

            this.call.sendAppMessage('playable');
          });

          this.call.on('participant-left', (e) => {
            if (!e) return;
            const audio = document.querySelector(`audio[data-participant-id="${e.participant.session_id}"]`);
            if (audio) audio.remove();
          });

          this.call.on('app-message', (e) => {
            if (!e) return;
            if (e.data === 'listening') {
              this.emit('call-start');
            } else {
              try {
                const msg = JSON.parse(e.data);
                this.emit('message', msg);
                if (msg.type === 'status-update' && msg.status === 'ended') {
                  this.hasEmittedCallEndedStatus = true;
                }
              } catch(err) {
                console.warn('Failed to parse app message:', err);
              }
            }
          });

          // Monitor audio levels for speech detection
          this.call.startRemoteParticipantsAudioLevelObserver(100);
          this.call.on('remote-participants-audio-level', (e) => {
            if (!e) return;

            const speechLevel = Object.values(e.participantsAudioLevel).reduce((a, b) => a + b, 0);
            this.emit('volume-level', Math.min(1, speechLevel / 0.15));

            const isSpeaking = speechLevel > 0.01;
            if (!isSpeaking) return;

            if (this.speakingTimeout) {
              clearTimeout(this.speakingTimeout);
            } else {
              this.emit('speech-start');
            }

            this.speakingTimeout = setTimeout(() => {
              this.emit('speech-end');
              this.speakingTimeout = null;
            }, 1000);
          });

          // Join the call
          await this.call.join({
            url: webCall.webCallUrl,
            subscribeToTracksAutomatically: false
          });

          // Enable noise cancellation
          await this.call.updateInputSettings({
            audio: {
              processor: {
                type: 'noise-cancellation'
              }
            }
          }).catch(() => {
            // Fallback if noise cancellation not available
          });

          return webCall;
        } catch (error) {
          console.error('Vapi start error:', error);
          this.emit('error', error);
          this.cleanup();
          return null;
        }
      }

      stop() {
        if (this.call) {
          this.call.destroy();
        }
        this.cleanup();
      }

      cleanup() {
        this.started = false;
        this.hasEmittedCallEndedStatus = false;
        this.call = null;
        this.speakingTimeout = null;
      }

      setMuted(mute) {
        if (this.call) {
          this.call.setLocalAudio(!mute);
        }
      }

      isMuted() {
        return this.call ? this.call.localAudio() === false : false;
      }

      send(message) {
        if (this.call) {
          this.call.sendAppMessage(JSON.stringify(message));
        }
      }

      say(message, endCallAfterSpoken, interruptionsEnabled) {
        this.send({
          type: 'say',
          message,
          endCallAfterSpoken,
          interruptionsEnabled: interruptionsEnabled ?? false
        });
      }
    }

    // Expose to window
    window.Vapi = Vapi;

    // Dispatch ready event
    window.dispatchEvent(new Event('vapi-ready'));
  }

  // Initialize immediately if Daily is already loaded, otherwise wait
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initVapi);
  } else {
    initVapi();
  }
})();
